-- Ajouter les FAQs locales pour serrurier
INSERT INTO service_city_faqs (service_id, city_id, position, question, answer, published) VALUES

-- Lille FAQs
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 1, 'Pouvez-vous intervenir en urgence à Lille ?', 'Oui, nos serruriers se déplacent sous 30 à 45 minutes dans Lille intra-muros, y compris Vieux-Lille, Wazemmes et Vauban. Dépannage prioritaire la nuit et le week-end.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 2, 'Ouverture de porte : abîmez-vous la serrure ?', 'Nous privilégions les méthodes non destructives (radio, crochetage fin). Si la serrure est endommagée ou trop sécurisée, nous proposons immédiatement un remplacement.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 3, 'Quels types de serrures installez-vous à Lille ?', 'Nous posons des cylindres européens, serrures multipoints 3 à 7 points certifiées A2P, verrous et solutions connectées. Nous adaptons selon votre budget et vos besoins.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 4, 'Intervenez-vous après effraction ?', 'Oui, nous sécurisons immédiatement la porte fracturée, posons un cylindre provisoire et établissons un devis détaillé agréé assurances.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 5, 'Proposez-vous des portes blindées à Lille ?', 'Oui, installation de blindages et portes blindées certifiées BP1 à BP3, avec cornières anti-pinces et renforts de huisseries.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 6, 'Quels quartiers de Lille couvrez-vous ?', 'Nous intervenons partout : Vieux-Lille, Centre, Vauban, Wazemmes, Fives, Hellemmes, Lomme et périphérie (Mons, La Madeleine, Lambersart).', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 7, 'Puis-je être remboursé par mon assurance après cambriolage ?', 'Oui. Nous vous remettons facture et attestation conformes pour remboursement auprès de votre assurance habitation.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'lille'), 8, 'Faites-vous aussi des audits sécurité à Lille ?', 'Oui, nous analysons portes, serrures et fenêtres, et proposons un devis clair pour renforcer vos accès.', true),

-- Vieux-Lille FAQs
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 1, 'Intervenez-vous dans les immeubles anciens du Vieux-Lille ?', 'Oui. Nous protégeons les parties communes, limitons le bruit et utilisons des techniques d''ouverture fines adaptées aux portes anciennes.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 2, 'Les portes anciennes acceptent-elles les serrures multipoints ?', 'Oui, après ajustements : renfort huisserie, pose discrète. Nous proposons des modèles compatibles avec le bâti ancien.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 3, 'Comment sécurisez-vous un appartement ancien après effraction ?', 'Nous posons un cylindre provisoire, renforçons la porte et remettons un devis assurances. Nous intervenons souvent rue Royale, rue Basse, rue Esquermoise.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 4, 'Quels délais pour une ouverture de porte claquée au Vieux-Lille ?', '30 à 45 minutes selon circulation et accès (rues étroites). Nos serruriers connaissent les contraintes locales.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 5, 'Installez-vous des serrures connectées en appartement ancien ?', 'Oui, serrures électroniques compatibles badges ou smartphones, adaptées aux portes existantes.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 6, 'Proposez-vous un blindage discret ?', 'Oui, blindage intérieur ou cornières anti-pinces, intégrés esthétiquement sans dénaturer la façade.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 7, 'Coordonnez-vous avec les syndics ?', 'Oui, pour accès aux parties communes, gestion badges VIGIK et autorisations d''intervention.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'vieux-lille'), 8, 'Votre travail est-il couvert par une garantie ?', 'Oui, garantie décennale sur les ouvrages et garantie biennale sur les équipements installés.', true),

-- Villeneuve-d'Ascq FAQs
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 1, 'Pouvez-vous intervenir en résidence étudiante à Villeneuve-d''Ascq ?', 'Oui, nous intervenons régulièrement dans les campus (Pont-de-Bois, Triolo, Hôtel de Ville). Délais rapides pour portes claquées ou clés perdues.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 2, 'Quels types de serrures conseillez-vous pour les maisons ascquoises ?', 'Nous recommandons serrures multipoints 5 à 7 points A2P pour maisons de Brigode, Flers-Bourg, Annappes.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 3, 'Faites-vous des interventions le soir et week-end ?', 'Oui, nous assurons un service 24/7 pour urgences (perte de clés, cambriolage).', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 4, 'Remplacez-vous aussi les portes après effraction ?', 'Oui, en coordination avec nos menuisiers partenaires. Sécurisation immédiate et devis assurance fourni.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 5, 'Installez-vous des verrous additionnels ?', 'Oui, verrous de sûreté, barres de blocage, solutions connectées simples pour studios.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 6, 'Proposez-vous des solutions PMR/seniors ?', 'Oui, poignées adaptées, serrures à clés ergonomiques, barres de renfort faciles à manipuler.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 7, 'Quels délais pour changer un cylindre ?', 'Remplacement sous 2 h en moyenne sur Villeneuve-d''Ascq et communes voisines.', true),
((SELECT id FROM services WHERE slug = 'serrurier'), (SELECT id FROM cities WHERE slug = 'villeneuve-d-ascq'), 8, 'Puis-je avoir un devis gratuit ?', 'Oui, nos devis sont gratuits et détaillés, remis avant toute intervention.', true),

